import React, { useState } from 'react';
import Cookie from 'cookie-universal';
import { useNavigate } from 'react-router-dom';
import '../../Styles/Auth.css';

export default function Login() {
    const [form, setForm] = useState({
        email: '',
        password: ''
    });
    const [loading, setLoading] = useState(false);
    const [err, setErr] = useState('');

    const cookie = Cookie();
    const navigate = useNavigate();

    function handleChange(e) {
        setForm({ ...form, [e.target.name]: e.target.value });
    }

    async function handleSubmit(e) {
        e.preventDefault();
        setLoading(true);
        setErr('');

        try {
            // استخدام fetch بدلاً من axios
            const response = await fetch('http://127.0.0.1:8000/api/login', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Accept': 'application/json'
                },
                body: JSON.stringify({
                    email: form.email,
                    password: form.password
                })
            });

            const data = await response.json();

            if (!response.ok) {
                throw new Error(data.message || 'فشل تسجيل الدخول');
            }

            console.log('Login Success:', data);

            const token = data.token;
            const user = data.user;

            cookie.set('educational-token', token);
            cookie.set('educational-user', JSON.stringify(user));

            setLoading(false);
            window.location.pathname = '/';

        } catch (error) {
            setLoading(false);
            console.error('Login Error:', error);
            setErr(error.message || 'حدث خطأ في تسجيل الدخول');
        }
    }

    return (
        <div className="auth-container">
            <div className="auth-box">
                <h2>تسجيل الدخول</h2>
                <p className="auth-subtitle">مرحباً بعودتك!</p>

                {err && <div className="error-message">{err}</div>}

                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label>البريد الإلكتروني</label>
                        <input
                            type="email"
                            name="email"
                            value={form.email}
                            onChange={handleChange}
                            placeholder="example@email.com"
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label>كلمة المرور</label>
                        <input
                            type="password"
                            name="password"
                            value={form.password}
                            onChange={handleChange}
                            placeholder="أدخل كلمة المرور"
                            required
                        />
                    </div>

                    <button type="submit" className="auth-btn" disabled={loading}>
                        {loading ? 'جاري تسجيل الدخول...' : 'تسجيل الدخول'}
                    </button>
                </form>

                <p className="auth-footer">
                    ليس لديك حساب؟ <a href="/register">إنشاء حساب</a>
                </p>
            </div>
        </div>
    );
}
